//zos.alipayobjects.com/rmsportal/jkjgkEfvpUPVyRjUImniVslZfWPnJuuZ.doc',\n    },\n    {\n      uid: '-4',\n      name: 'image.png',\n      status: 'error',\n    },\n    {\n      uid: '-5',\n      name: 'pdf.pdf',\n      status: 'error',\n    },\n    {\n      uid: '-6',\n      name: 'doc.doc',\n      status: 'error',\n    },\n  ]);\n  const handlePreview = async file => {\n    if (!file.url && !file.preview) {\n      file.preview = await getBase64(file.originFileObj);\n    }\n    setPreviewOpen(true);\n    setPreviewImage(file.url || file.preview);\n  };\n  const handleChange = ({ fileList: newFileList }) => setFileList(newFileList);\n  const handleIconRender = (file, listType) => {\n    const fileSufIconList = [\n      { type: <FilePdfTwoTone />, suf: ['.pdf'] },\n      { type: <FileExcelTwoTone />, suf: ['.xlsx', '.xls', '.csv'] },\n      { type: <FileWordTwoTone />, suf: ['.doc', '.docx'] },\n      {\n        type: <PictureTwoTone />,\n        suf: ['.webp', '.svg', '.png', '.gif', '.jpg', '.jpeg', '.jfif', '.bmp', '.dpg'],\n      },\n    ];\n    // console.log(1, file, listType);\n    let icon = file.status === 'uploading' ? <LoadingOutlined /> : <PaperClipOutlined />;\n    if (listType === 'picture' || listType === 'picture-card' || listType === 'picture-circle') {\n      if (listType === 'picture-card' && file.status === 'uploading') {\n        icon = <LoadingOutlined />; // or icon = 'uploading...';\n      } else {\n        fileSufIconList.forEach(item => {\n          if (item.suf.includes(file.name.slice(file.name.lastIndexOf('.')))) {\n            icon = item.type;\n          }\n        });\n      }\n    }\n    return icon;\n  };\n  const uploadButton = (\n    <button style={{ border: 0, background: 'none' }} type=\"button\">\n      <PlusOutlined />\n      <div style={{ marginTop: 8 }}>Upload</div>\n    </button>\n  );\n  return (\n    <>\n      <Upload\n        action=\"https://660d2bd96ddfa2943b33731c.mockapi.io/api/upload\"\n        listType=\"picture-card\"\n        fileList={fileList}\n        onPreview={handlePreview}\n        onChange={handleChange}\n        iconRender={handleIconRender}\n      >\n        {fileList.length >= 8 ? null : uploadButton}\n      </Upload>\n      {previewImage && (\n        <Image\n          styles={{ root: { display: 'none' } }}\n          preview={{\n            open: previewOpen,\n            onOpenChange: visible => setPreviewOpen(visible),\n            afterOpenChange: visible => !visible && setPreviewImage(''),\n          }}\n          src={previewImage}\n        />\n      )}\n    </>\n  );\n};\nexport default App;\n",description:"<p>根据类型默认显示对应 icon</p>"}},{demo:{id:"upload-demo-upload-custom-action-icon",loader:()=>e.A(181387),version:"60cf2b6e"},previewerProps:{title:"自定义交互图标和文件信息",filename:"components/upload/demo/upload-custom-action-icon.tsx",pkgDependencyList:{"@ant-design/compatible":"^5.1.4","@ant-design/happy-work-theme":"^2.0.0","@ant-design/static-style-extract":"^2.1.0","@ant-design/tools":"^19.2.0","@ant-design/x":"^2.7.0","@ant-design/x-sdk":"^2.7.0","@antfu/eslint-config":"~9.2.0","@biomejs/biome":"^2.5.0","@blazediff/core":"^1.9.1","@codecov/webpack-plugin":"^2.0.1","@codesandbox/sandpack-react":"^2.20.0","@dnd-kit/core":"^6.3.1","@dnd-kit/modifiers":"^9.0.0","@dnd-kit/sortable":"^10.0.0","@dnd-kit/utilities":"^3.2.2","@emotion/react":"^11.14.0","@emotion/server":"^11.11.0","@eslint-react/eslint-plugin":"^5.8.6","@google/design.md":"^0.3.0","@ianvs/prettier-plugin-sort-imports":"^4.7.1","@inquirer/prompts":"^8.4.2","@madccc/duplicate-package-checker-webpack-plugin":"^1.0.0","@microflash/rehype-figure":"^2.1.4","@npmcli/run-script":"^11.0.0","@octokit/rest":"^22.0.1","@prettier/sync":"^0.6.1","@rc-component/virtual-list":"^1.0.2","@size-limit/file":"^12.1.0","@stackblitz/sdk":"^1.11.0","@testing-library/dom":"^10.4.1","@testing-library/jest-dom":"^7.0.0","@testing-library/react":"^16.3.2","@testing-library/user-event":"^14.6.1","@types/adm-zip":"^0.5.8","@types/ali-